import os

def lire_log(chemin):
    if not os.path.exists(chemin):
        print(f"Fichier introuvable : {chemin}")
        return []
    try:
        with open(chemin, "r", encoding="utf-8", errors="ignore") as f:
            return f.readlines()
    except PermissionError:
        print(f"Permission refusée : {chemin}")
        return []
    except Exception as e:
        print(f"Erreur : {e}")
        return []

lignes = lire_log(r"C:\Windows\System32\drivers\etc\hosts")
print(f"{len(lignes)} lignes lues")
```

`encoding="utf-8", errors="ignore"` évite les erreurs sur les fichiers avec des caractères spéciaux.
